template-output.format:
── COOKIE Workflow Engine ──────────────────────────────
Workflow:   {workflow.name}
Episode:    {episode_id} (if applicable, otherwise "N/A")
Mode:       {current_execution_mode}
Skills:     {loaded_skills_list}
─────────────────────────────────────────────────────────
{workflow.description}
─────────────────────────────────────────────────────────

invoke-protocol.input:
workflow_id: {workflow.name}
status: {final_status}  (success / partial / failed)
outputs: {list of all files created/modified}
errors: {list of any errors encountered}
warnings: {list of any warnings}
cost_summary: {from FINAL-2}
flagged_assets: {list of assets that were flagged but accepted}
next_suggested: {next workflow in the pipeline, if determinable}

template-output.format:
── Workflow Complete ──────────────────────────────────
Workflow:  {workflow.name}
Status:    {final_status}
Duration:  {execution_duration}
Mode:      {execution_mode} {mode_changes_if_any}

Outputs:
{for each output: "  - {output_path}"}

Cost Summary:
  Spent:    ${total_spent}
  Estimate: ${original_estimate} ({variance_percent})
  Retakes:  {retake_count} (${retake_cost})

{if errors exist:}
Errors:
{for each error: "  - {error_description}"}

{if flagged_assets exist:}
Flagged Assets (accepted with warnings):
{for each flagged: "  - {asset_id}: {reason}"}

{if production_state_updated:}
Production State:
  Flags set:  {production_state_flags_set}
  Status:     {old_status} → {new_status}

{if next_suggested:}
Next: {next_suggested_description}
Hint: Run {next_suggested_command} to continue.
─────────────────────────────────────────────────────────
